async function main() {
  console.log(`Inserting ${questions.length} questions...`);
  let inserted = 0;
  for (const q of questions) {
    await pool.query(
      `INSERT INTO questions (topic_id, text, options, correct_option, explanation, difficulty)
       VALUES ($1, $2, $3::text[], $4, $5, $6)`,
      [q.topicId, q.text, q.options, q.correctOption, q.explanation, q.difficulty]
    );
    inserted++;
    if (inserted % 50 === 0) console.log(`  ${inserted}/${questions.length} done`);
  }
  console.log(`\n✅ Done! Inserted ${inserted} questions.`);
  await pool.end();
}

main().catch(console.error);
